import{c as t,S as i,j as s,m as a}from"./chunks/framework.BXgR76oC.js";const c=JSON.parse('{"title":"GitHub App Setup","description":"","frontmatter":{},"headers":[],"relativePath":"guide/github-app-setup.md","filePath":"guide/github-app-setup.md","lastUpdated":1779781690000}'),l={name:"guide/github-app-setup.md"};function r(d,e,n,h,o,p){return i(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="github-app-setup" tabindex="-1">GitHub App Setup <a class="header-anchor" href="#github-app-setup" aria-label="Permalink to “GitHub App Setup”">​</a></h1><p>The GitHub App is the maintainer/install surface. GitHub OAuth is the MCP user-auth surface.</p><h2 id="basic-fields" tabindex="-1">Basic Fields <a class="header-anchor" href="#basic-fields" aria-label="Permalink to “Basic Fields”">​</a></h2><p>Use these values:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Homepage URL</td><td><code>https://gittensory.aethereal.dev</code></td></tr><tr><td>Webhook URL</td><td><code>\${GITTENSORY_API_URL}/v1/github/webhook</code></td></tr><tr><td>Webhook active</td><td>enabled</td></tr><tr><td>SSL verification</td><td>enabled</td></tr><tr><td>Device Flow</td><td>enabled</td></tr></tbody></table><p><code>GITTENSORY_API_URL</code> is the private API origin for the deployed backend. Do not use the GitHub Pages docs domain for webhooks; Pages only serves static docs.</p><p>Use a generated webhook secret and set the same value in Cloudflare as <code>GITHUB_WEBHOOK_SECRET</code>.</p><h2 id="required-repository-permissions" tabindex="-1">Required Repository Permissions <a class="header-anchor" href="#required-repository-permissions" aria-label="Permalink to “Required Repository Permissions”">​</a></h2><table tabindex="0"><thead><tr><th>Permission</th><th>Access</th><th>Why</th></tr></thead><tbody><tr><td>Metadata</td><td>Read</td><td>Required for repository identity and repository events.</td></tr><tr><td>Checks</td><td>Write</td><td>Required to create and update the Gittensory check run.</td></tr><tr><td>Pull requests</td><td>Read</td><td>Required for PR metadata, reviewability, and webhook events.</td></tr><tr><td>Issues</td><td>Read</td><td>Required for issue linkage, issue-discovery context, and duplicate signals.</td></tr></tbody></table><p>Optional:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Access</th><th>Why</th></tr></thead><tbody><tr><td>Issues</td><td>Write</td><td>Only needed if public-safe sticky PR comments are enabled.</td></tr><tr><td>Contents</td><td>Read</td><td>Only needed if a future feature reads repository files directly through the App.</td></tr></tbody></table><h2 id="required-events" tabindex="-1">Required Events <a class="header-anchor" href="#required-events" aria-label="Permalink to “Required Events”">​</a></h2><p>Subscribe to:</p><ul><li>Pull request</li><li>Issues</li><li>Repository</li></ul><p>If GitHub shows <code>Installation target</code>, select it. Some installation-related events are not always shown as normal selectable event rows; Gittensory should not block health on event names that are hidden in the app UI.</p><h2 id="install-or-repair" tabindex="-1">Install Or Repair <a class="header-anchor" href="#install-or-repair" aria-label="Permalink to “Install Or Repair”">​</a></h2><ol><li>Update the GitHub App permissions and events.</li><li>Reinstall the app or approve the changed permissions.</li><li>Select the repos Gittensory should inspect.</li><li>Trigger installation-health refresh:</li></ol><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$GITTENSORY_API_URL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/v1/internal/jobs/refresh-installation-health/run&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$INTERNAL_JOB_TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><ol start="5"><li>Check health:</li></ol><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$GITTENSORY_API_URL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/v1/readiness&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$GITTENSORY_API_TOKEN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>Healthy app installation state should remove the readiness warning about GitHub App installations needing attention.</p><h2 id="marketplace-readiness" tabindex="-1">Marketplace Readiness <a class="header-anchor" href="#marketplace-readiness" aria-label="Permalink to “Marketplace Readiness”">​</a></h2><p>Before Marketplace submission, add:</p><ul><li>public docs URL</li><li>support contact</li><li>privacy policy</li><li>terms page if needed</li><li>clear setup flow</li><li>valid webhook and install diagnostics</li></ul><p>Do not submit until the privacy, support, terms, install diagnostics, and public setup flow are complete.</p>`,25)])])}const k=t(l,[["render",r]]);export{c as __pageData,k as default};
